<?php
namespace App\Http\Controllers\Inventory; use App\Http\Controllers\Controller; use App\Models\Inventory\{InventoryBalance,InventoryCategory,InventoryItem,InventoryStockOpname,InventoryTransaction};
class InventoryDashboardController extends Controller{public function __invoke(){return view('inventory.dashboard.index',['totalCategories'=>InventoryCategory::count(),'totalItems'=>InventoryItem::count(),'totalQuantity'=>InventoryBalance::sum('quantity'),'byCondition'=>InventoryBalance::selectRaw('inventory_condition_id,sum(quantity) total')->with('condition')->groupBy('inventory_condition_id')->get(),'byLocation'=>InventoryBalance::selectRaw('inventory_location_id,sum(quantity) total')->with('location')->groupBy('inventory_location_id')->get(),'recentTransactions'=>InventoryTransaction::with('item','toLocation','fromLocation')->latest()->limit(8)->get(),'openOpnames'=>InventoryStockOpname::with('location')->where('status','!=','completed')->latest()->limit(8)->get(),'alerts'=>InventoryBalance::with('item','condition','location')->where('quantity','>',0)->whereHas('condition',fn($q)=>$q->whereIn('code',['RUSAK_BERAT','HILANG','TIDAK_LAYAK']))->limit(8)->get()]);}}
